INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/01/31 12:00:00", 3.414, 190805, 2, 1, "2030/01/01 14:59:59", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 0.0, 1, 1000001, 62, -416.5, "カリン", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/01/31 12:00:00", 3.099, 190805, 2, 2, "2030/01/01 14:59:59", "ミッションをクリアして、\n報酬をゲットしましょう！", 0.0, 1, 1000002, 62, -416.5, "カリン", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/01/31 12:00:00", 2.801, 190805, 2, 3, "2030/01/01 14:59:59", "受け取ることができる\n報酬があるようです\n確認してみてください", 0.0, 1, 1000003, 63, -416.5, "カリン", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/01/31 12:00:00", 0.0, 190805, 2, 4, "2030/01/01 14:59:59", "報酬がもらえますよ！\nチェックしてみてください", 0.0, 1, 1000004, 63, -416.5, "カリン", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/01/31 12:00:00", 2.12, 190805, 1, 5, "2030/01/01 14:59:59", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 0.0, 1, 1000005, 64, -363.0, "カリン", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/01/31 12:00:00", 1.68, 190805, 2, 6, "2030/01/01 14:59:59", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 0.0, 1, 1000006, 64, -363.0, "カリン", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/01/31 12:00:00", 2.33, 190805, 1, 7, "2030/01/01 14:59:59", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 0.0, 1, 1000007, 64, -363.0, "カリン", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/01/31 12:00:00", 5.18, 133701, 7, 101, "2030/01/01 14:59:59", "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", -6.0, 10201, 1020101, 61, -285.0, "ラビリスタ", 3);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/01/31 12:00:00", 8.77, 133901, 2, 201, "2030/01/01 14:59:59", "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", -2.0, 10201, 1020102, 61, -285.0, "クリスティーナ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/01/31 12:00:00", 15.5, 133801, 1, 301, "2030/01/01 14:59:59", "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 0.0, 10201, 1020103, 61, -285.0, "ネネカ", 6);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/02/28 12:00:00", 9.061, 134301, 5, 101, "2030/01/01 14:59:59", "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 0.0, 10202, 1020201, 61, -285.0, "ランファ", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/02/28 12:00:00", 7.699, 134401, 2, 201, "2030/01/01 14:59:59", "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 0.0, 10202, 1020202, 61, -285.0, "チカ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/03/31 12:00:00", 8.595, 134601, 2, 101, "2030/01/01 14:59:59", "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 0.0, 10203, 1020301, 61, -285.0, "アオイ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/03/31 12:00:00", 7.758, 134501, 2, 201, "2030/01/01 14:59:59", "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 0.0, 10203, 1020302, 61, -285.0, "クローチェ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/04/30 12:00:00", 7.0, 132302, 6, 101, "2030/01/01 14:59:59", "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 0.0, 10204, 1020401, 61, -285.0, "ルイズマリー", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/04/30 12:00:00", 7.904, 132402, 2, 201, "2030/01/01 14:59:59", "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 0.0, 10204, 1020402, 61, -285.0, "イロハ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/04/30 12:00:00", 8.487, 132502, 2, 301, "2030/01/01 14:59:59", "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 0.0, 10204, 1020403, 61, -285.0, "ソノ", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/05/31 12:00:00", 8.763, 134901, 2, 101, "2030/01/01 14:59:59", "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 0.0, 10205, 1020502, 61, -285.0, "カノン", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/05/31 12:00:00", 6.417, 134801, 3, 201, "2030/01/01 14:59:59", "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 0.0, 10205, 1020503, 61, -285.0, "ツムギ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/06/30 12:00:00", 10.335, 135001, 7, 101, "2030/01/01 14:59:59", "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 0.0, 10206, 1020601, 61, -285.0, "エリス", 3);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/06/30 12:00:00", 6.281, 135101, 4, 201, "2030/01/01 14:59:59", "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 0.0, 10206, 1020602, 61, -285.0, "シェフィ", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/06/30 12:00:00", 12.244, 135201, 2, 301, "2030/01/01 14:59:59", "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 0.0, 10206, 1020603, 61, -285.0, "プレシア", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/07/31 12:00:00", 6.339, 135301, 8, 101, "2030/01/01 14:59:59", "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 0.0, 10207, 1020701, 61, -285.0, "クリア", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/07/31 12:00:00", 8.184, 135401, 9, 201, "2030/01/01 14:59:59", "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 0.0, 10207, 1020702, 61, -285.0, "アネモネ", 7);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/08/31 12:00:00", 3.906, 129101, 2, 101, "2030/01/01 14:59:59", "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 0.0, 10208, 1020801, 61, -285.0, "アイラ", 9);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/08/31 12:00:00", 14.465, 129201, 2, 201, "2030/01/01 14:59:59", "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 0.0, 10208, 1020802, 61, -285.0, "シナツ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/08/31 12:00:00", 8.662, 100101, 3, 301, "2030/01/01 14:59:59", "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 0.0, 10208, 1020803, 61, -285.0, "ヒヨリ", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/08/31 12:00:00", 10.915, 100301, 3, 401, "2030/01/01 14:59:59", "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 0.0, 10208, 1020804, 61, -285.0, "レイ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/09/30 12:00:00", 6.042, 135802, 7, 101, "2030/01/01 14:59:59", "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 0.0, 10209, 1020901, 61, -285.0, "ユキノ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/09/30 12:00:00", 9.402, 135903, 1, 201, "2030/01/01 14:59:59", "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 0.0, 10209, 1020902, 61, -285.0, "サツキ", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/09/30 12:00:00", 8.16, 136902, 1, 301, "2030/01/01 14:59:59", "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 0.0, 10209, 1020903, 61, -285.0, "ルルィ", 8);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/10/31 12:00:00", 5.0, 137401, 2, 101, "2030/01/01 14:59:59", "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 0.0, 10210, 1021001, 61, -285.0, "カスミ", 3);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/10/31 12:00:00", 8.12, 136001, 1, 201, "2030/01/01 14:59:59", "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 0.0, 10210, 1021002, 61, -285.0, "アラクネ", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/10/31 12:00:00", 6.386, 136202, 2, 301, "2030/01/01 14:59:59", "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 0.0, 10210, 1021003, 61, -285.0, "ナーナ", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/11/30 12:00:00", 7.438, 136402, 4, 101, "2030/01/01 14:59:59", "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 0.0, 10211, 1021101, 61, -285.0, "ユイ", 3);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/11/30 12:00:00", 8.35, 136302, 5, 201, "2030/01/01 14:59:59", "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 0.0, 10211, 1021102, 61, -285.0, "ミソラ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/12/31 12:00:00", 5.0, 136501, 2, 101, "2030/01/01 14:59:59", "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 0.0, 10212, 1021201, 61, -285.0, "シズル", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/12/31 12:00:00", 5.25, 137902, 2, 201, "2030/01/01 14:59:59", "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 0.0, 10212, 1021202, 61, -285.0, "リノ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2025/12/31 12:00:00", 7.5, 106801, 2, 301, "2030/01/01 14:59:59", "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 0.0, 10212, 1021203, 61, -285.0, "ラビリスタ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/01/31 12:00:00", 8.204, 126501, 2, 101, "2030/01/01 14:59:59", "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 0.0, 10213, 1021301, 61, -285.0, "ライラエル", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/01/31 12:00:00", 7.176, 129701, 2, 201, "2030/01/01 14:59:59", "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 0.0, 10213, 1021302, 61, -285.0, "ネフィ＝ネラ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/01/31 12:00:00", 8.602, 133101, 5, 301, "2030/01/01 14:59:59", "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 0.0, 10213, 1021303, 61, -285.0, "ヴァイオレット", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/02/06 12:00:00", 10.14, 138101, 3, 102, "2030/01/01 14:59:59", "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 0.0, 10213, 1021304, 61, -285.0, "ライラエル", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/02/06 12:00:00", 10.152, 138201, 7, 202, "2030/01/01 14:59:59", "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 0.0, 10213, 1021305, 61, -285.0, "ネフィ＝ネラ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/02/06 12:00:00", 9.688, 138001, 3, 302, "2030/01/01 14:59:59", "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 0.0, 10213, 1021306, 61, -285.0, "ヴァイオレット", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/02/12 12:00:00", 5.928, 138301, 1, 401, "2030/01/01 14:59:59", "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 0.0, 10213, 1021307, 61, -285.0, "ペコリーヌ", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/02/28 12:00:00", 9.19, 138702, 2, 101, "2030/01/01 14:59:59", "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 0.0, 10214, 1021401, 61, -285.0, "ワカナ", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/02/28 12:00:00", 8.724, 138802, 3, 201, "2030/01/01 14:59:59", "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 0.0, 10214, 1021402, 61, -285.0, "シオリ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/03/31 12:00:00", 7.758, 138902, 1, 101, "2030/01/01 14:59:59", "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 0.0, 10215, 1021501, 61, -285.0, "グレイス", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/03/31 12:00:00", 6.375, 139002, 4, 201, "2030/01/01 14:59:59", "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 0.0, 10215, 1021502, 61, -285.0, "キョウカ", 6);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/03/31 12:00:00", 6.173, 136902, 1, 301, "2030/01/01 14:59:59", "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 0.0, 10215, 1021503, 61, -285.0, "ルルィ", 6);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/04/30 12:00:00", 4.202, 139202, 2, 101, "2030/01/01 14:59:59", "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 0.0, 10216, 1021601, 61, -285.0, "ミホ", 6);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/04/30 12:00:00", 2.842, 139302, 1, 201, "2030/01/01 14:59:59", "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 0.0, 10216, 1021602, 61, -285.0, "マホ", 6);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/04/30 12:00:00", 4.598, 139402, 1, 301, "2030/01/01 14:59:59", "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 0.0, 10216, 1021603, 61, -285.0, "エリカ", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/05/31 12:00:00", 6.533, 125802, 3, 101, "2030/01/01 14:59:59", "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", 0.0, 10217, 1021701, 61, -285.0, "リリ", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/05/31 12:00:00", 5.0, 126102, 3, 301, "2030/01/01 14:59:59", "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", 0.0, 10217, 1021702, 61, -285.0, "プレシア", 3);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/05/31 12:00:00", 5.214, 126002, 4, 201, "2030/01/01 14:59:59", "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", 0.0, 10217, 1021703, 61, -285.0, "クリア", 3);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/05/31 12:00:00", 8.781, 139501, 3, 102, "2030/01/01 14:59:59", "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", 0.0, 10217, 1021704, 61, -285.0, "リリ", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/05/31 12:00:00", 6.529, 139601, 1, 202, "2030/01/01 14:59:59", "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", 0.0, 10217, 1021705, 61, -285.0, "クリア", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/05/31 12:00:00", 3.195, 139701, 2, 302, "2030/01/01 14:59:59", "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", 0.0, 10217, 1021706, 61, -285.0, "プレシア", 3);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/06/30 12:00:00", 12.43, 139902, 3, 101, "2030/01/01 14:59:59", "ダーリンと一緒に南の島で\nリゾート開発なんて夢みたい♪\nああ…幸せ、最高の夏だわ…\n触れたら爆発さえしなければ～…っ", 0.0, 10218, 1021801, 61, -285.0, "ルイズマリー", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/06/30 12:00:00", 6.35, 140001, 3, 201, "2030/01/01 14:59:59", "青い空、白い雲…無人島リゾートで\n大儲けですわ～♪　こらこらそこ、\nイチャついてるんじゃないですのよ\n触れたらドカンですわよ、ドカン！", 0.0, 10218, 1021802, 61, -285.0, "クレジッタ", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/04/10 12:00:00", 3.414, 190801, 2, 1, "2030/01/01 14:59:59", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 0.0, 2, 2000001, 62, -416.5, "カリン", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/04/10 12:00:00", 3.099, 190801, 2, 2, "2030/01/01 14:59:59", "ミッションをクリアして、\n報酬をゲットしましょう！", 0.0, 2, 2000002, 62, -416.5, "カリン", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/04/10 12:00:00", 2.801, 190801, 2, 3, "2030/01/01 14:59:59", "受け取ることができる\n報酬があるようです\n確認してみてください", 0.0, 2, 2000003, 63, -416.5, "カリン", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/04/10 12:00:00", 0.0, 190801, 2, 4, "2030/01/01 14:59:59", "報酬がもらえますよ！\nチェックしてみてください", 0.0, 2, 2000004, 63, -416.5, "カリン", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/04/10 12:00:00", 2.12, 190801, 1, 5, "2030/01/01 14:59:59", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 0.0, 2, 2000005, 64, -363.0, "カリン", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/04/10 12:00:00", 1.68, 190801, 2, 6, "2030/01/01 14:59:59", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 0.0, 2, 2000006, 64, -363.0, "カリン", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES ("2026/04/10 12:00:00", 2.33, 190801, 1, 7, "2030/01/01 14:59:59", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 0.0, 2, 2000007, 64, -363.0, "カリン", 2);
